package arch.day30;

import java.util.*;
import java.util.stream.*;

public class Day30Basic {
    public static void main(String[] args) {
        List<Integer> xs = List.of(1, 2, 3, 4, 5);
        int s = xs.stream().filter(x -> x % 2 == 0).mapToInt(x -> x).sum();
        System.out.println(s);
    }
