package arch.day30;

import java.util.*;
import java.util.stream.*;

public class Day30LimitSkip {
    public static void main(String[] args) {
        List<Integer> xs = IntStream.rangeClosed(1, 20).boxed().toList();
        List<Integer> page = xs.stream().skip(5).limit(3).toList();
        System.out.println(page);
        // takeWhile: Java 9+
        List<Integer> head = xs.stream().takeWhile(n -> n < 4).toList();
        System.out.println(head);
    }
}

