public class Day30Reduce {
    public static void main(String[] args) {
        OptionalInt o = IntStream.of(2, 3, 4).reduce(Integer::sum);
        System.out.println(o.getAsInt());
        String folded = Stream.of("a", "b", "c").reduce("", String::concat);
        System.out.println(folded);
